mapper.sql:
SELECT A.VOC_SEQ ,A.CONTRACT_NUM ,TO_CHAR(B.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM ,FN_GET_ORGNM(B.VOC_AGNT_CD) || '/' || B.VOC_AGNT_CD AS VOC_AGNT_CD_NAME ,FN_GET_CODENM('ACEN0006', B.VOC_SUB_CTG_CD) AS VOC_SUB_CTG_CD_NAME ,TO_CHAR(TO_DATE(B.DUE_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS DUE_DT ,FN_GET_CODENM('ACEN0005', B.STATUS) AS STATUS_NAME ,B.VOC_CONTENT ,B.ANS_CONTENT ,B.CALL_CONTENT ,DECODE(B.REGST_ID, 'ACEN', B.REGST_ID, FN_GET_USRNM(B.REGST_ID)) AS REGST_NAME FROM NMCP_ACEN_VOC_REQ@DL_MCP A ,NMCP_ACEN_VOC_HIST@DL_MCP B WHERE A.REQ_SEQ = B.REQ_SEQ AND A.REQ_SEQ = #{reqSeq}
AND A.VOC_AGNT_CD = #{cntpntShopId}
AND A.STATUS != '00'
ORDER BY B.SEQ DESC

mapper.update:
/*AcenVocMapper.updateAcenVocInfo*/
UPDATE NMCP_ACEN_VOC_REQ@DL_MCP
SET RVISN_ID = #{sessionUserId}
   ,RVISN_DTTM = SYSDATE

	 ,VOC_AGNT_CD = #{vocAgntCd}


	 ,STATUS = #{status}


	 ,DUE_DT = #{dueDt}


	 ,ANS_CONTENT = #{ansContent}


	 ,CALL_CONTENT = #{callContent}

WHERE REQ_SEQ = #{reqSeq}
